class Solution:
    def countKeyChanges(self, s: str) -> int:
        if not s:
            return 0

        changes = 0
        for i in range(1, len(s)):
            # Only case-insensitive comparison matters.
            # If the letter differs ignoring case, it's a key change.
            if s[i].lower() != s[i - 1].lower():
                changes += 1
        return changes
```

